  1→package com.taskflow.security;
  2→
  3→import org.junit.jupiter.api.DisplayName;
  4→import org.junit.jupiter.api.Nested;
  5→import org.junit.jupiter.api.Test;
  6→import org.springframework.beans.factory.annotation.Autowired;
  7→import org.springframework.boot.test.autoconfigure.web.servlet.AutoConfigureMockMvc;
  8→import org.springframework.boot.test.context.SpringBootTest;
  9→import org.springframework.test.context.ActiveProfiles;
 10→import org.springframework.test.web.servlet.MockMvc;
 11→
 12→import static org.springframework.test.web.servlet.request.MockMvcRequestBuilders.get;
 13→import static org.springframework.test.web.servlet.request.MockMvcRequestBuilders.post;
 14→import static org.springframework.test.web.servlet.result.MockMvcResultMatchers.status;
 15→
 16→/**
 17→ * Integration tests for SecurityConfig filter chain configuration.
 18→ *
 19→ * Verifies:
 20→ * - /api/auth/** endpoints are publicly accessible (permitAll)
 21→ * - Other /api/** endpoints require authentication (401 without token)
 22→ * - H2 console is accessible (permitAll)
 23→ * - JWT filter is integrated into the filter chain
 24→ *
 25→ * Uses full Spring Boot context with MockMvc.
 26→ */
 27→@SpringBootTest
 28→@AutoConfigureMockMvc
 29→@ActiveProfiles("test")
 30→@DisplayName("SecurityConfig Integration Tests")
 31→class SecurityConfigIntegrationTest {
 32→
 33→    @Autowired
 34→    private MockMvc mockMvc;
 35→
 36→    @Nested
 37→    @DisplayName("Public Endpoints (permitAll)")
 38→    class PublicEndpoints {
 39→
 40→        @Test
 41→        @DisplayName("should permit POST /api/auth/register without authentication")
 42→        void shouldPermitRegisterWithoutAuth() throws Exception {
 43→            mockMvc.perform(post("/api/auth/register")
 44→                            .contentType("application/json")
 45→                            .content("{\"username\":\"test\",\"password\":\"password123\",\"displayName\":\"Test\"}"))
 46→                    .andExpect(result ->
 47→                            org.assertj.core.api.Assertions.assertThat(
 48→                                    result.getResponse().getStatus()).isNotEqualTo(401));
 49→            // Note: may return 404 if controller not implemented, but NOT 401
 50→        }
 51→
 52→        @Test
 53→        @DisplayName("should permit POST /api/auth/login without authentication")
 54→        void shouldPermitLoginWithoutAuth() throws Exception {
 55→            mockMvc.perform(post("/api/auth/login")
 56→                            .contentType("application/json")
 57→                            .content("{\"username\":\"test\",\"password\":\"password123\"}"))
 58→                    .andExpect(result ->
 59→                            org.assertj.core.api.Assertions.assertThat(
 60→                                    result.getResponse().getStatus()).isNotEqualTo(401));
 61→        }
 62→    }
 63→
 64→    @Nested
 65→    @DisplayName("Protected Endpoints (require authentication)")
 66→    class ProtectedEndpoints {
 67→
 68→        @Test
 69→        @DisplayName("should return 401 for GET /api/tasks without token")
 70→        void shouldReturn401ForTasksWithoutToken() throws Exception {
 71→            mockMvc.perform(get("/api/tasks"))
 72→                    .andExpect(status().isUnauthorized());
 73→        }
 74→
 75→        @Test
 76→        @DisplayName("should return 401 for POST /api/tasks without token")
 77→        void shouldReturn401ForPostTasksWithoutToken() throws Exception {
 78→            mockMvc.perform(post("/api/tasks")
 79→                            .contentType("application/json")
 80→                            .content("{\"title\":\"Test Task\"}"))
 81→                    .andExpect(status().isUnauthorized());
 82→        }
 83→
 84→        @Test
 85→        @DisplayName("should permit GET /api/auth/me at security filter level (permitAll on /api/auth/**)")
 86→        void shouldPermitAuthMeAtSecurityFilterLevel() throws Exception {
 87→            // /api/auth/me is under /api/auth/** which is permitAll in SecurityConfig.
 88→            // The 401 for unauthenticated /api/auth/me comes from the controller, not the security filter.
 89→            // So the security filter should NOT block this request.
 90→            mockMvc.perform(get("/api/auth/me"))
 91→                    .andExpect(result ->
 92→                            org.assertj.core.api.Assertions.assertThat(
 93→                                    result.getResponse().getStatus()).isNotEqualTo(403));
 94→            // Note: may return 404 (no controller) or 401 (controller-level check), but NOT 403 (forbidden by security)
 95→        }
 96→    }
 97→
 98→    @Nested
 99→    @DisplayName("JWT Filter Integration")
100→    class JwtFilterIntegration {
101→
102→        @Test
103→        @DisplayName("should return 401 when Authorization header has invalid token")
104→        void shouldReturn401WithInvalidToken() throws Exception {
105→            mockMvc.perform(get("/api/tasks")
106→                            .header("Authorization", "Bearer invalid.jwt.token"))
107→                    .andExpect(status().isUnauthorized());
108→        }
109→
110→        @Test
111→        @DisplayName("should return 401 when Authorization header has expired token")
112→        void shouldReturn401WithExpiredToken() throws Exception {
113→            // An obviously invalid/expired token
114→            mockMvc.perform(get("/api/tasks")
115→                            .header("Authorization", "Bearer eyJhbGciOiJIUzI1NiJ9.eyJzdWIiOiIxIiwiZXhwIjoxfQ.invalid"))
116→                    .andExpect(status().isUnauthorized());
117→        }
118→    }
119→
120→    @Nested
121→    @DisplayName("Stateless Session Policy")
122→    class StatelessSessionPolicy {
123→
124→        @Test
125→        @DisplayName("should not create HTTP session for requests")
126→        void shouldNotCreateSession() throws Exception {
127→            mockMvc.perform(get("/api/tasks"))
128→                    .andExpect(result -> {
129→                        // Session should not be created for stateless config
130→                        org.assertj.core.api.Assertions.assertThat(
131→                                result.getRequest().getSession(false)
132→                        ).isNull();
133→                    });
134→        }
135→    }
136→}
