  7→import org.junit.jupiter.api.Nested;
  8→import org.junit.jupiter.api.Test;
  9→import org.springframework.beans.factory.annotation.Autowired;
 10→import org.springframework.boot.test.autoconfigure.orm.jpa.DataJpaTest;
 11→import org.springframework.boot.test.autoconfigure.orm.jpa.TestEntityManager;
 12→import org.springframework.data.domain.Page;
 13→import org.springframework.data.domain.PageRequest;
 14→import org.springframework.data.domain.Pageable;
 15→
 16→import java.util.List;
 17→
 18→import static org.junit.jupiter.api.Assertions.*;
 19→
 20→/**
 21→ * Integration tests for TaskRepository custom queries.
 22→ * Uses @DataJpaTest with embedded H2.
 23→ */
 24→@DataJpaTest
 25→class TaskRepositoryTest {
 26→
 27→    @Autowired
 28→    private TaskRepository taskRepository;
 29→
 30→    @Autowired
 31→    private TestEntityManager entityManager;
 32→
 33→    private Task createTask(String title, Task.Priority priority, boolean deleted) {
 34→        Task task = new Task();
 35→        task.setTitle(title);
 36→        task.setPriority(priority);
 37→        task.setCreatedBy(1L);
 38→        task.setDeleted(deleted);
 39→        return entityManager.persistAndFlush(task);
 40→    }
 41→
 42→    private Task createTask(String title) {
 43→        return createTask(title, Task.Priority.MEDIUM, false);
 44→    }
 45→
 46→    // ── Soft-delete exclusion ──────────────────────────────────────────
 47→
 48→    @Nested
 49→    @DisplayName("findByDeletedFalse — soft-delete exclusion")
 50→    class SoftDeleteTests {
 51→
 52→        @Test
 53→        @DisplayName("Excludes soft-deleted tasks from results")
 54→        void shouldExcludeSoftDeletedTasks() {
 55→            createTask("Active Task 1");
 56→            createTask("Active Task 2");
 57→            createTask("Deleted Task", Task.Priority.MEDIUM, true);
 58→
 59→            entityManager.clear();
 60→
 61→            Page<Task> result = taskRepository.findByDeletedFalse(PageRequest.of(0, 20));
 62→            assertEquals(2, result.getTotalElements());
 63→            assertTrue(result.getContent().stream().noneMatch(Task::isDeleted));
 64→        }
 65→
 66→        @Test
 67→        @DisplayName("Returns empty page when all tasks are soft-deleted")
 68→        void shouldReturnEmptyWhenAllDeleted() {
 69→            createTask("Deleted 1", Task.Priority.MEDIUM, true);
 70→            createTask("Deleted 2", Task.Priority.HIGH, true);
 71→
 72→            entityManager.clear();
 73→
 74→            Page<Task> result = taskRepository.findByDeletedFalse(PageRequest.of(0, 20));
 75→            assertEquals(0, result.getTotalElements());
 76→            assertTrue(result.getContent().isEmpty());
 77→        }
 78→
 79→        @Test
 80→        @DisplayName("Returns all tasks when none are soft-deleted")
